import pandas as pd
import numpy as np
from sklearn.preprocessing import LabelEncoder
from scipy.stats import f_oneway
import os

DATA_DIR = os.path.join(os.path.dirname(__file__), '..', 'Datasets')
RESPONSES_DIR = os.path.join(os.path.dirname(__file__), '..', 'LLM_Responses')

gpt35_responses  = pd.read_csv(os.path.join(DATA_DIR, 'gpt3.5_responses.csv'))
llama2_responses = pd.read_csv(os.path.join(DATA_DIR, 'llama2_responses.csv'))
human_responses  = pd.read_csv(os.path.join(DATA_DIR, 'survey_responses.csv'))

# 2026 model responses — generated by the new response notebooks
NEW_MODELS = {}
for model_file, label in [
    ('gpt4o_responses.csv', 'gpt4o'),
    ('claude_responses.csv', 'claude'),
    ('llama31_responses.csv', 'llama31'),
]:
    path = os.path.join(DATA_DIR, model_file)
    if os.path.exists(path):
        NEW_MODELS[label] = pd.read_csv(path)

questions_of_interest = [
    "What is the biggest challenge you face as a developer?",
    "When choosing a programming language for a new project, you prioritize:",
    "How do you balance between innovation and meeting project deadlines?"
]


def run_anova(groups: dict, label: str = "") -> dict:
    """Run one-way ANOVA for each question across all provided respondent groups.

    groups: dict mapping label -> DataFrame, each with 'Question' and 'Answer' columns.
    Human responses use 'Option' column; LLM responses use 'Answer'.
    """
    results = {}
    for question in questions_of_interest:
        encoded_arrays = []
        # Collect all answers across groups to fit a shared LabelEncoder
        all_answers = []
        per_group = {}
        for name, df in groups.items():
            col = 'Option' if 'Option' in df.columns else 'Answer'
            mask = df['Question'].str.contains(question, case=False, na=False)
            vals = df.loc[mask, col].dropna().astype(str).tolist()
            per_group[name] = vals
            all_answers.extend(vals)

        if not all_answers:
            continue

        le = LabelEncoder()
        le.fit(all_answers)
        for name, vals in per_group.items():
            if vals:
                encoded_arrays.append(le.transform(vals))

        if len(encoded_arrays) >= 2:
            result = f_oneway(*encoded_arrays)
            results[question] = {
                'label': label,
                'groups': list(groups.keys()),
                'F': result.statistic,
                'p': result.pvalue,
            }

    return results


# --- 2023 baseline ---
baseline_groups = {
    'human':  human_responses,
    'gpt35':  gpt35_responses,
    'llama2': llama2_responses,
}
results_2023 = run_anova(baseline_groups, label='2023_baseline')

# --- 2026 new models (only if CSVs exist) ---
if NEW_MODELS:
    new_groups = {'human': human_responses, **NEW_MODELS}
    results_2026 = run_anova(new_groups, label='2026_new')

    # --- Longitudinal: all six groups together ---
    all_groups = {**baseline_groups, **NEW_MODELS}
    results_longitudinal = run_anova(all_groups, label='longitudinal')

for question, res in results_2023.items():
    print(f"[{res['label']}] {question}")
    print(f"  Groups: {res['groups']}")
    print(f"  F={res['F']:.4f}  p={res['p']:.4f}\n")

if NEW_MODELS:
    for question, res in results_2026.items():
        print(f"[{res['label']}] {question}")
        print(f"  Groups: {res['groups']}")
        print(f"  F={res['F']:.4f}  p={res['p']:.4f}\n")
